"use strict";(()=>{window.Webflow||(window.Webflow=[]);window.Webflow.push(()=>{let t=document.querySelector('[data="dd-block"]'),e=document.querySelector('[data="dd-header"]'),d=document.querySelector('[data="dd-table"]');t?.addEventListener("click",()=>{e?.classList.contains("active")?(e.classList.remove("active"),d?.classList.remove("active")):(e?.classList.add("active"),d?.classList.add("active"))})});})();
